const nextIssueNumber = `-- name: NextIssueNumber :one

INSERT INTO issue_counters (repo_id, next)
VALUES ($1, 2)
ON CONFLICT (repo_id) DO UPDATE SET next = issue_counters.next + 1
RETURNING (next - 1)::BIGINT AS number
`

// ---- issue_counters ----
// Atomic per-repo issue counter. RETURNS the value just claimed; the row
// initialiser starts at 2 because the first claim must return 1.
// Explicit BIGINT cast on the SELECT side so sqlc emits int64 rather
// than narrowing to int32 on the `next - 1` arithmetic.
func (q *Queries) NextIssueNumber(ctx context.Context, repoID int64) (int64, error) {
	row := q.db.QueryRow(ctx, nextIssueNumber, repoID)
	var number int64
	err := row.Scan(&number)
	return number, err
}

const planSubtree = `-- name: PlanSubtree :many

WITH RECURSIVE plan_tree AS (
    SELECT i.id, i.number, i.title, i.state, i.agent_role,
           i.parent_id,
           i.actor_kind,
           COALESCE(i.actor_user_id, 0)::BIGINT AS actor_user_id,
           i.actor_role_key,
           i.actor_display_name,
           0::INT AS depth,
           ARRAY[i.number] AS path
    FROM issues i
    WHERE i.id = $1
  UNION ALL
    SELECT i.id, i.number, i.title, i.state, i.agent_role,
           i.parent_id,
           i.actor_kind,
           COALESCE(i.actor_user_id, 0)::BIGINT AS actor_user_id,
           i.actor_role_key,
           i.actor_display_name,
           pt.depth + 1,
           pt.path || i.number
    FROM issues i
    JOIN plan_tree pt ON i.parent_id = pt.id
    WHERE pt.depth < 32
)
SELECT id, number, title, state, agent_role,
       COALESCE(parent_id, 0)::BIGINT AS parent_id,
       actor_kind, actor_user_id, actor_role_key, actor_display_name,
       depth::INT
FROM plan_tree
ORDER BY path
`

type PlanSubtreeRow struct {
	ID               int64
	Number           int64
	Title            string
	State            string
	AgentRole        string
	ParentID         int64
	ActorKind        string
	ActorUserID      int64
	ActorRoleKey     string
	ActorDisplayName string
	Depth            int32
}

// ---- plan subtree (recursive CTE for the whole tree) ----
// Returns every issue in the subtree rooted at root_id, including the root,
// with depth for tree rendering. Ordered depth-first by number.
func (q *Queries) PlanSubtree(ctx context.Context, rootID int64) ([]PlanSubtreeRow, error) {
	rows, err := q.db.Query(ctx, planSubtree, rootID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []PlanSubtreeRow{}
	for rows.Next() {
		var i PlanSubtreeRow
		if err := rows.Scan(
			&i.ID,
			&i.Number,
			&i.Title,
			&i.State,
			&i.AgentRole,
			&i.ParentID,
			&i.ActorKind,
			&i.ActorUserID,
			&i.ActorRoleKey,
			&i.ActorDisplayName,
			&i.Depth,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

